solution: class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        int len1 = s1.size(), len2 = s2.size();
        vector<int> repeatCnt(n1 + 1, 0);
        vector<int> nextIdx(n1 + 1, 0);
        int j = 0, cnt = 0;
        for (int k = 1; k <= n1; ++k) {
            for (int i = 0; i < len1; ++i) {
                if (s1[i] == s2[j]) {
                    ++j;
                    if (j == len2) {
                        j = 0;
                        ++cnt;
                    }
                }
            }
            repeatCnt[k] = cnt;
            nextIdx[k] = j;
            for (int p = 0; p < k; ++p) {
                if (nextIdx[p] == j) {
                    int prevCnt = repeatCnt[p];
                    int patternCnt = repeatCnt[k] - repeatCnt[p];
                    int patternLen = k - p;
                    int remaining = n1 - p;
                    int fullPatterns = remaining / patternLen;
                    int remainder = remaining % patternLen;
                    int total = prevCnt + fullPatterns * patternCnt + (repeatCnt[p + remainder] - repeatCnt[p]);
                    return total / n2;
                }
            }
        }
        return repeatCnt[n1] / n2;
    }
};
efficiency: HIGH
time complexity: O(n1 * len1)
space complexity: O(n1)
energy implications: LOW
explanation: Uses pattern detection to avoid full simulation. Tracks repeats and next index after each s1 block; when a cycle is found, computes the total repeats via arithmetic instead of iteration, drastically reducing runtime for large n1.

